import { formatUser } from './user.js';

const logs = [];

export function createLog(type, message, user) {
  const entry = {
    type,
    message,
    user: user ? formatUser(user) : null,
    timestamp: Date.now(),
  };
  logs.push(entry);
  return entry;
}

export function getLogs() {
  return [...logs];
}

export function clearLogs() {
  logs.length = 0;
}

