import { createUser, formatUser } from './src/user.js';
import { createLog, getLogs, clearLogs } from './src/logger.js';
import { validateEmail, validateName } from './src/validator.js';
import assert from 'node:assert/strict';

// Test basic functionality
clearLogs();

const user = createUser('Alice', 'alice@example.com');
assert.equal(user.name, 'Alice');
assert.equal(user.email, 'alice@example.com');
assert.ok(user.id);

assert.equal(formatUser(user), 'Alice <alice@example.com>');

assert.ok(validateEmail('test@test.com'));
assert.ok(!validateEmail('invalid'));
assert.ok(validateName('Bob'));
assert.ok(!validateName(''));

// Test logging works
const logs = getLogs();
assert.ok(logs.length > 0, 'Should have logged user creation');
assert.equal(logs[0].type, 'user_created');

// Test logging with user formatting
clearLogs();
createLog('test', 'test message', user);
const testLogs = getLogs();
assert.equal(testLogs[0].user, 'Alice <alice@example.com>');

// Test validation logging
clearLogs();
assert.throws(() => createUser('Bad', 'notanemail'));
const validationLogs = getLogs();
assert.ok(validationLogs.some(l => l.type === 'validation_failed'));

console.log('All tests passed');
